@Component
class AuthorizationCodeRepository {
    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();

    public void save(AuthorizationCode authCode) {
        codes.put(authCode.getCode(), authCode);
        cleanupExpiredCodes();
    }

    public AuthorizationCode findByCode(String code) {
        cleanupExpiredCodes();
        return codes.get(code);
    }

    public void delete(String code) {
        codes.remove(code);
    }

    private void cleanupExpiredCodes() {
        codes.entrySet().removeIf(entry -> entry.getValue().isExpired());
    }
}

@Component
class RedirectUriValidator {
    
    public boolean isValid(String redirectUri, Set<String> registeredUris) {
        if (redirectUri == null || redirectUri.isEmpty()) {
            return false;
        }

        try {
            URI uri = new URI(redirectUri);
            
            if (!"https".equals(uri.getScheme()) && !"http".equals(uri.getScheme())) {
                return false;
            }
            
            String host = uri.getHost();
            if (host == null || host.isEmpty()) {
                return false;
            }

            for (String registeredUri : registeredUris) {
                if (isExactMatch(redirectUri, registeredUri)) {
                    return true;
                }
                
                if (isValidWithRegisteredBase(uri, registeredUri)) {
                    return true;
                }
            }
            
            return false;
        } catch (URISyntaxException e) {
            return false;
        }
    }

    private boolean isExactMatch(String redirectUri, String registeredUri) {
        return redirectUri.equals(registeredUri);
    }

    private boolean isValidWithRegisteredBase(URI redirectUri, String registeredUriStr) {
        try {
            URI registeredUri = new URI(registeredUriStr);
            
            if (!redirectUri.getScheme().equals(registeredUri.getScheme())) {
                return false;
            }

            String redirectHost = redirectUri.getHost();
            String registeredHost = registeredUri.getHost();
            
            if (!isHostValid(redirectHost, registeredHost)) {
                return false;
            }

            int redirectPort = redirectUri.getPort();
            int registeredPort = registeredUri.getPort();
            if (redirectPort != registeredPort) {
                return false;
            }

            String redirectPath = redirectUri.getPath() != null ? redirectUri.getPath() : "";
            String registeredPath = registeredUri.getPath() != null ? registeredUri.getPath() : "";
            
            if (!redirectPath.startsWith(registeredPath)) {
                return false;
            }

            return true;
        } catch (URISyntaxException e) {
            return false;
        }
    }

    private boolean isHostValid(String redirectHost, String registeredHost) {
        if (redirectHost.equals(registeredHost)) {
            return true;
        }

        String[] redirectParts = redirectHost.split("\\.");
        String[] registeredParts = registeredHost.split("\\.");

        if (redirectParts.length < 2 || registeredParts.length < 2) {
            return false;
        }

        int redirectLen = redirectParts.length;
        int registeredLen = registeredParts.length;

        if (redirectLen < registeredLen) {
            return false;
        }

        for (int i = 0; i < registeredLen; i++) {
            String redirectPart = redirectParts[redirectLen - 1 - i];
            String registeredPart = registeredParts[registeredLen - 1 - i];
            
            if (!redirectPart.equals(registeredPart)) {
                return false;
            }
        }

        for (int i = 0; i < redirectLen - registeredLen; i++) {
            String subdomainPart = redirectParts[i];
            if (!isValidSubdomainPart(subdomainPart)) {
                return false;
            }
        }

        return true;
    }

    private boolean isValidSubdomainPart(String part) {
        if (part == null || part.isEmpty() || part.length() > 63) {
            return false;
        }
        
        Pattern pattern = Pattern.compile("^[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?$");
        return pattern.matcher(part).matches();
    }
}

