    public OAuth2Controller(ClientRepository clientRepository,
                           AuthorizationCodeRepository authorizationCodeRepository,
                           RedirectUriValidator redirectUriValidator,
                           CodeGenerator codeGenerator) {
        this.clientRepository = clientRepository;
        this.authorizationCodeRepository = authorizationCodeRepository;
        this.redirectUriValidator = redirectUriValidator;
        this.codeGenerator = codeGenerator;
    }

    @GetMapping("/oauth/authorize")
    public Object authorize(
            @RequestParam("response_type") String responseType,
            @RequestParam("client_id") String clientId,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam(value = "scope", required = false) String scope,
            @RequestParam(value = "state", required = false) String state) {

        if (!"code".equals(responseType)) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "unsupported_response_type"));
        }

        Client client = clientRepository.findByClientId(clientId);
        if (client == null) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_client"));
        }

        if (!redirectUriValidator.isValid(redirectUri, client.getRegisteredRedirectUris())) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_redirect_uri", 
                                 "error_description", "The redirect_uri does not match any registered URI"));
        }

        String userId = "user123";

        String code = codeGenerator.generateCode();
        AuthorizationCode authCode = new AuthorizationCode(code, clientId, redirectUri, scope, userId);
        authorizationCodeRepository.save(authCode);

        StringBuilder redirectUrl = new StringBuilder(redirectUri);
        redirectUrl.append(redirectUri.contains("?") ? "&" : "?");
        redirectUrl.append("code=").append(code);
        if (state != null && !state.isEmpty()) {
            redirectUrl.append("&state=").append(state);
        }

        return "redirect:" + redirectUrl.toString();
    }

    @PostMapping("/oauth/token")
    @ResponseBody
    public ResponseEntity<?> token(
            @RequestParam("grant_type") String grantType,
            @RequestParam("code") String code,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam("client_id") String clientId,
            @RequestParam("client_secret") String clientSecret) {

        if (!"authorization_code".equals(grantType)) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "unsupported_grant_type"));
        }

        Client client = clientRepository.findByClientId(clientId);
        if (client == null || !client.getClientSecret().equals(clientSecret)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body(Map.of("error", "invalid_client"));
        }

        AuthorizationCode authCode = authorizationCodeRepository.findByCode(code);
        if (authCode == null) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_grant"));
        }

        if (authCode.isExpired()) {
            authorizationCodeRepository.delete(code);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_grant", "error_description", "Authorization code expired"));
        }

        if (!authCode.getClientId().equals(clientId)) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_grant"));
        }

        if (!authCode.getRedirectUri().equals(redirectUri)) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "invalid_grant"));
        }

        authorizationCodeRepository.delete(code);

        String accessToken = codeGenerator.generateToken();
        AccessToken token = new AccessToken(accessToken, "Bearer", 3600, authCode.getScope());

        Map<String, Object> response = new HashMap<>();
        response.put("access_token", token.getToken());
        response.put("token_type", token.getTokenType());
        response.put("expires_in", token.getExpiresIn());
        if (token.getScope() != null) {
            response.put("scope", token.getScope());
        }

        return ResponseEntity.ok(response);
    }

